Here's how to test `DataFetcher` with proper timeout/cancellation handling using modern MSTest 3.x+:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // --- Happy path ---

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("hello"),
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    // --- Error status code ---

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.NotFound,
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // --- Caller-initiated cancellation ---

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WhenCancelled_ThrowsOperationCanceledException()
    {
        // Arrange — handler that blocks until cancellation fires
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct); // blocks forever
            return new HttpResponseMessage();       // never reached
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout via [Timeout] + TestContext.CancellationToken ---

    [TestMethod]
    [Timeout(500)] // test fails if FetchAsync doesn't respect cancellation within 500 ms
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct);
            return new HttpResponseMessage();
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // TestContext.CancellationToken fires when [Timeout] expires,
        // proving FetchAsync cooperatively cancels.
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // --- Reusable fake handler ---

    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage response)
            : this((_, _) => Task.FromResult(response)) { }

        public FakeHandler(
            Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Mock `HttpClient`** | Custom `HttpMessageHandler` — no mocking library needed |
| **Cooperative timeout** | `[Timeout(ms)]` + `_testContext.CancellationToken` — MSTest fires the token when time expires |
| **Caller cancellation** | Create a `CancellationTokenSource`, cancel it, assert `TaskCanceledException` |
| **Slow-server simulation** | `Task.Delay(Timeout.Infinite, ct)` blocks until the token fires |
| **Error codes** | `Assert.ThrowsExactlyAsync` verifies `EnsureSuccessStatusCode` throws |

The critical insight: **always pass `_testContext.CancellationToken`** to your async calls in tests with `[Timeout]`. This lets MSTest cooperatively cancel the test instead of abandoning a hung thread.
